1	#include <cutlass/cutlass.h>
2	
3	#include "utils.h"
4	
5	#include "params.h"
6	#include "config.h"
7	#include "traits.h"
8	
9	using namespace cute;
10	using cutlass::arch::NamedBarrier;
11	
12	namespace sm90 {
13	
14	// Here we use MAX_INIT_VAL_SM to initialize sM, and MAX_INIT_VAL for masking
15	// The reason is that, we need to calculate new_max = max(sM(row_idx), cur_max*scale_softmax_log2)
16	// so we must guarantee that MAX_INIT_VAL*scale_softmax_log2 < MAX_INIT_VAL_SM
17	static constexpr float MAX_INIT_VAL_SM = -1e30f;
18	static constexpr float MAX_INIT_VAL = -1e33f;
19	
20	__forceinline__ __device__ int get_AorC_row_idx(int local_row_idx, int idx_in_warpgroup) {
21	    // In the layout of fragment A and fragment C during WGMMA, data each thread holds resides in two particular rows. This function converts the local_row_idx (0~2) to the actual row_idx
22	    // You may refer to this link for the detailed layout: https://docs.nvidia.com/cuda/parallel-thread-execution/#wgmma-64n16-a
23	    int row_idx = (idx_in_warpgroup/32)*16 + local_row_idx*8 + (idx_in_warpgroup%32/4);
24	    return row_idx;
25	}
26	
27	// Launch TMA copy for a range of KV tile
28	// A tile has a shape of PAGE_BLOCK_SIZE (64) x 64
29	template<
30	    int START_HEAD_DIM_TILE_IDX,
31	    int END_HEAD_DIM_TILE_IDX,
32	    typename TMA_K_OneTile,
33	    typename Engine0, typename Layout0,
34	    typename Engine1, typename Layout1
35	>
36	__forceinline__ __device__ void launch_kv_tiles_copy_tma(
37	    Tensor<Engine0, Layout0> const &gKV,	// (PAGE_BLOCK_SIZE, HEAD_DIM_K)
38	    Tensor<Engine1, Layout1> &sKV,	// (PAGE_BLOCK_SIZE, HEAD_DIM_K), swizzled
39	    TMA_K_OneTile &tma_K,
40	    TMABarrier* barriers_K,
41	    int idx_in_warpgroup
42	) {
43	    if (idx_in_warpgroup == 0) {
44	        auto thr_tma = tma_K.get_slice(_0{});
45	        Tensor cur_gKV = thr_tma.partition_S(gKV)(_, _0{}, Int<START_HEAD_DIM_TILE_IDX>{});
46	        Tensor cur_sKV = thr_tma.partition_D(sKV)(_, _0{}, Int<START_HEAD_DIM_TILE_IDX>{});
47	        cute::copy(tma_K.with(reinterpret_cast<typename TMABarrier::ValueType &>(barriers_K[START_HEAD_DIM_TILE_IDX]), 0, cute::TMA::CacheHintSm90::EVICT_FIRST), cur_gKV, cur_sKV);
48	        if constexpr (START_HEAD_DIM_TILE_IDX+1 < END_HEAD_DIM_TILE_IDX) {
49	            launch_kv_tiles_copy_tma<START_HEAD_DIM_TILE_IDX+1, END_HEAD_DIM_TILE_IDX>(gKV, sKV, tma_K, barriers_K, idx_in_warpgroup);
50	        }
51	    }
52	}
53	
54	// Prefetch some KV tiles
55	// Currently this is not used because it leads to performance degradation
56	template<
57	    int START_HEAD_DIM_TILE_IDX,
58	    int END_HEAD_DIM_TILE_IDX,
59	    typename TMA_K_OneTile,
60	    typename Engine0, typename Layout0
61	>
62	__forceinline__ __device__ void prefetch_kv_tiles(
63	    Tensor<Engine0, Layout0> const &gKV,	// (PAGE_BLOCK_SIZE, HEAD_DIM_K)
64	    TMA_K_OneTile &tma_K,
65	    int idx_in_warpgroup
66	) {
67	    if (idx_in_warpgroup == 0) {
68	        auto thr_tma = tma_K.get_slice(_0{});
69	        Tensor cur_gKV = thr_tma.partition_S(gKV)(_, _0{}, Int<START_HEAD_DIM_TILE_IDX>{});
70	        cute::prefetch(tma_K, cur_gKV);
71	        if constexpr (START_HEAD_DIM_TILE_IDX+1 < END_HEAD_DIM_TILE_IDX) {
72	            prefetch_kv_tiles<START_HEAD_DIM_TILE_IDX+1, END_HEAD_DIM_TILE_IDX>(gKV, tma_K, idx_in_warpgroup);
73	        }
74	    }
75	}
76	
77	// Adapted from https://github.com/Dao-AILab/flash-attention/blob/cdaf2de6e95cb05400959b5ab984f66e4c7df317/hopper/utils.h
78	// * Copyright (c) 2024, Tri Dao.
79	template <bool zero_init=false, int wg_wait=0, bool arrive=true, bool commit=true, typename Tensor0, typename Tensor1, typename Tensor2, typename TiledMma>
80	__forceinline__ __device__ void gemm(TiledMma &tiled_mma, Tensor0 const &tCrA, Tensor1 const &tCrB, Tensor2 &tCrC) {
81	    constexpr bool Is_RS = !cute::is_base_of<cute::GMMA::DescriptorIterator, typename TiledMma::FrgTypeA>::value;
82	    // Need to cast away const on tCrA since warpgroup_fence_operand doesn't take const
83	    if constexpr (Is_RS) { cute::warpgroup_fence_operand(const_cast<Tensor0 &>(tCrA)); }
84	    warpgroup_fence_operand(tCrC);
85	    if constexpr (arrive) {
86	        warpgroup_arrive();
87	    }
88	    if constexpr (zero_init) {
89	        tiled_mma.accumulate_ = GMMA::ScaleOut::Zero;
90	        // Unroll the K mode manually to set scale D to 1
91	        CUTLASS_PRAGMA_UNROLL
92	        for (int k_block = 0; k_block < size<2>(tCrA); ++k_block) {
93	            cute::gemm(tiled_mma, tCrA(_,_,k_block), tCrB(_,_,k_block), tCrC);
94	            tiled_mma.accumulate_ = GMMA::ScaleOut::One;
95	        }
96	    } else {
97	        // cute::gemm(tiled_mma, tCrA, tCrB, tCrC);
98	        // Unroll the K mode manually to set scale D to 1
99	        CUTLASS_PRAGMA_UNROLL
100	        for (int k_block = 0; k_block < size<2>(tCrA); ++k_block) {
101	            cute::gemm(tiled_mma, tCrA(_,_,k_block), tCrB(_,_,k_block), tCrC);
102	            tiled_mma.accumulate_ = GMMA::ScaleOut::One;
103	        }
104	    }
105	    if constexpr (commit) {
106	        warpgroup_commit_batch();
107	    }
108	    if constexpr (wg_wait >= 0) { warpgroup_wait<wg_wait>(); }
109	    warpgroup_fence_operand(tCrC);
110	    if constexpr (Is_RS) { warpgroup_fence_operand(const_cast<Tensor0 &>(tCrA)); }
111	}
112	
113	
114	// Wait for one KV-tile to be ready, and then calculate P += Q K^T for one Q-tile (BLOCK_SIZE_Mx64) and one KV-tile (PAGE_BLOCK_SIZEx64)
115	// The Q-tile should be in shared memory
116	template<
117	    typename TiledMMA,
118	    typename Engine0, typename Layout0,
119	    typename Engine1, typename Layout1,
120	    typename Engine2, typename Layout2
121	> 
122	__forceinline__ __device__ void qkt_gemm_one_tile_sQ(
123	    TiledMMA &tiled_mma,
124	    Tensor<Engine0, Layout0> const &thr_mma_sQ_tile,	// (MMA, 1, 4)
125	    Tensor<Engine1, Layout1> const &thr_mma_sKV_tile,	// (MMA, 1, 4)
126	    Tensor<Engine2, Layout2> &rP,	// ((2, 2, 8), 1, 1)
127	    TMABarrier* barrier,
128	    bool &cur_phase,
129	    int idx_in_warpgroup
130	) {
131	    if (idx_in_warpgroup == 0) {
132	        barrier->arrive_and_expect_tx(64*64*2);
133	    }
134	    barrier->wait(cur_phase ? 1 : 0);
135	
136	    warpgroup_fence_operand(rP);
137	    warpgroup_arrive();
138	    cute::gemm(tiled_mma, thr_mma_sQ_tile(_, _, _0{}), thr_mma_sKV_tile(_, _, _0{}), rP);
139	    tiled_mma.accumulate_ = GMMA::ScaleOut::One;
140	    cute::gemm(tiled_mma, thr_mma_sQ_tile(_, _, _1{}), thr_mma_sKV_tile(_, _, _1{}), rP);
141	    cute::gemm(tiled_mma, thr_mma_sQ_tile(_, _, _2{}), thr_mma_sKV_tile(_, _, _2{}), rP);
142	    cute::gemm(tiled_mma, thr_mma_sQ_tile(_, _, _3{}), thr_mma_sKV_tile(_, _, _3{}), rP);
143	    warpgroup_commit_batch();
144	    warpgroup_fence_operand(rP);
145	}
146	
147	template<
148	    typename TiledMMA,
149	    typename Engine0, typename Layout0,
150	    typename Engine1, typename Layout1,
151	    typename Engine2, typename Layout2
152	> 
153	__forceinline__ __device__ void  qkt_gemm_one_tile_rQ(
154	    TiledMMA &tiled_mma,
155	    Tensor<Engine0, Layout0> const &thr_mma_rQ_tile,	// (MMA, 1, 4)
156	    Tensor<Engine1, Layout1> const &thr_mma_sKV_tile,	// (MMA, 1, 4)
157	    Tensor<Engine2, Layout2> &rP,	// ((2, 2, 8), 1, 1)
158	    TMABarrier* barrier,
159	    bool &cur_phase,
160	    int idx_in_warpgroup
161	) {
162	    if (idx_in_warpgroup == 0) {
163	        barrier->arrive_and_expect_tx(64*64*2);
164	    }
165	    barrier->wait(cur_phase ? 1 : 0);
166	
167	    warpgroup_fence_operand(const_cast<Tensor<Engine0, Layout0> &>(thr_mma_rQ_tile));
168	    warpgroup_fence_operand(rP);
169	    warpgroup_arrive();
170	    cute::gemm(tiled_mma, thr_mma_rQ_tile(_, _, _0{}), thr_mma_sKV_tile(_, _, _0{}), rP);
171	    tiled_mma.accumulate_ = GMMA::ScaleOut::One;
172	    cute::gemm(tiled_mma, thr_mma_rQ_tile(_, _, _1{}), thr_mma_sKV_tile(_, _, _1{}), rP);
173	    cute::gemm(tiled_mma, thr_mma_rQ_tile(_, _, _2{}), thr_mma_sKV_tile(_, _, _2{}), rP);
174	    cute::gemm(tiled_mma, thr_mma_rQ_tile(_, _, _3{}), thr_mma_sKV_tile(_, _, _3{}), rP);
175	    warpgroup_commit_batch();
176	    warpgroup_fence_operand(rP);
177	    warpgroup_fence_operand(const_cast<Tensor<Engine0, Layout0> &>(thr_mma_rQ_tile));
178	}
179	
180	// Pipelined TMA wait and Q K^T gemm
181	// In order to overlap memory copy (G->S copy for K) and computation, we divide both Q and K into tiles of shape (BLOCK_SIZE_M, 64), and (PAGE_BLOCK_SIZE, 64) respectively, and then do the computation as follows:
182	// - Wait for the 0-th tile to be ready using `barrier.wait()`
183	// - Compute Q K^T for the 0-th tile
184	// - Wait for the 1-st tile to be ready
185	// - Compute Q K^T for the 1-st tile
186	// ...
187	// This gives latter tiles more time to be ready, and thus can overlap the memory copy and computation
188	template<
189	    typename T, // Traits
190	    int PHASE_IDX,	// See comments in the code
191	    typename Engine0, typename Layout0,
192	    typename Engine1, typename Layout1,
193	    typename Engine2, typename Layout2,
194	    typename Engine3, typename Layout3
195	> 
196	__forceinline__ __device__ void warpgroup_cooperative_qkt_gemm(
197	    Tensor<Engine0, Layout0> &sQ,	// (BLOCK_SIZE_M, HEAD_DIM_K)
198	    Tensor<Engine1, Layout1> &sKV,	// (PAGE_BLOCK_SIZE, HEAD_DIM_K)
199	    Tensor<Engine2, Layout2> &rP,	// ((2, 2, 8), 1, 1)
200	    Tensor<Engine3, Layout3> &rQ8,	// The 8-th tile of Q. We store it separately to leave some room for storing sP1
201	    TMABarrier* barriers,
202	    bool &cur_phase,
203	    int idx_in_warpgroup
204	) {
205	    Tensor sQ_tiled = flat_divide(sQ, Shape<Int<T::BLOCK_SIZE_M>, _64>{})(_, _, _0{}, _);	// (BLOCK_SIZE_M, 64, 9)
206	    Tensor sKV_tiled = flat_divide(sKV, Shape<Int<T::PAGE_BLOCK_SIZE>, _64>{})(_, _, _0{}, _);	// (PAGE_BLOCK_SIZE, 64, 9)
207	    TiledMMA tiled_mma_sQ = (typename T::TiledMMA_QK_sQ){};
208	    ThrMMA thr_mma_sQ = tiled_mma_sQ.get_slice(idx_in_warpgroup);
209	    Tensor thr_mma_sQ_tiled = thr_mma_sQ.partition_fragment_A(sQ_tiled);	// (MMA, 1, 4, 9)
210	    Tensor thr_mma_sKV_tiled = thr_mma_sQ.partition_fragment_B(sKV_tiled);	// (MMA, 1, 4, 9)
211	    TiledMMA tiled_mma_rQ = (typename T::TiledMMA_QK_rQ){};
212	
213	    #define QKT_GEMM_ONE_TILE(TILE_IDX) \
214	        if constexpr(TILE_IDX != 8) { \
215	            qkt_gemm_one_tile_sQ(tiled_mma_sQ, thr_mma_sQ_tiled(_, _, _, Int<TILE_IDX>{}), thr_mma_sKV_tiled(_, _, _, Int<TILE_IDX>{}), rP, barriers + TILE_IDX, cur_phase, idx_in_warpgroup); \
216	        } else { \
217	            qkt_gemm_one_tile_rQ(tiled_mma_rQ, rQ8, thr_mma_sKV_tiled(_, _, _, Int<TILE_IDX>{}), rP, barriers + TILE_IDX, cur_phase, idx_in_warpgroup); \
218	        }
219	
220	    if constexpr (PHASE_IDX == 0) {
221	        // In PHASE-0, warpgroup 0 calculates Q K^T for the first 4 tiles
222	        tiled_mma_sQ.accumulate_ = GMMA::ScaleOut::Zero;
223	        tiled_mma_rQ.accumulate_ = GMMA::ScaleOut::One;
224	        QKT_GEMM_ONE_TILE(0);
225	        QKT_GEMM_ONE_TILE(1);
226	        QKT_GEMM_ONE_TILE(2);
227	        QKT_GEMM_ONE_TILE(3);
228	    } else if constexpr (PHASE_IDX == 1) {
229	        // In PHASE-1, warpgroup 1 calculates Q K^T for all the 9 tiles
230	        tiled_mma_sQ.accumulate_ = GMMA::ScaleOut::Zero;
231	        tiled_mma_rQ.accumulate_ = GMMA::ScaleOut::One;
232	        QKT_GEMM_ONE_TILE(4);
233	        QKT_GEMM_ONE_TILE(5);
234	        QKT_GEMM_ONE_TILE(6);
235	        QKT_GEMM_ONE_TILE(7);
236	        QKT_GEMM_ONE_TILE(8);
237	        QKT_GEMM_ONE_TILE(0);
238	        QKT_GEMM_ONE_TILE(1);
239	        QKT_GEMM_ONE_TILE(2);
240	        QKT_GEMM_ONE_TILE(3);
241	        cur_phase ^= 1;
242	    } else {
243	        // In PHASE-2, warpgroup 0 calculates Q K^T for the last 5 tiles
244	        static_assert(PHASE_IDX == 2);
245	        tiled_mma_sQ.accumulate_ = GMMA::ScaleOut::One;
246	        tiled_mma_rQ.accumulate_ = GMMA::ScaleOut::One;
247	        QKT_GEMM_ONE_TILE(4);
248	        QKT_GEMM_ONE_TILE(5);
249	        QKT_GEMM_ONE_TILE(6);
250	        QKT_GEMM_ONE_TILE(7);
251	        QKT_GEMM_ONE_TILE(8);
252	        cur_phase ^= 1;
253	    }
254	}
