322	template<
323	    typename T,
324	    bool DO_OOB_FILLING,
325	    typename Engine0, typename Layout0,
326	    typename Engine1, typename Layout1,
327	    typename Engine2, typename Layout2,
328	    typename Engine3, typename Layout3,
329	    typename Engine4, typename Layout4
330	>
331	__forceinline__ __device__ void wg0_bunch_0(
332	    Tensor<Engine0, Layout0> &rPb,	// ((2, 2, 8), 1, 1)
333	    Tensor<Engine1, Layout1> &rP0,	// ((2, 2, 8), 1, 1)
334	    Tensor<Engine2, Layout2> &rO0,	// ((2, 2, 32), 1, 1)
335	    Tensor<Engine3, Layout3> &sScale0,	// (BLOCK_SIZE_M)
336	    Tensor<Engine4, Layout4> &sM,	// (BLOCK_SIZE_M)
337	    float rL[2],
338	    int rRightBorderForQSeq[2],
339	    float scale_softmax_log2,
340	    int start_token_idx,
341	    int idx_in_warpgroup
342	) {
343	    // This piece of code is tightly coupled [Accumulate's layout](https://docs.nvidia.com/cuda/parallel-thread-execution/_images/wgmma-64N16-D.png)
344	    CUTLASS_PRAGMA_UNROLL
345	    for (int local_row_idx = 0; local_row_idx < 2; ++local_row_idx) {
346	        int row_idx = get_AorC_row_idx(local_row_idx, idx_in_warpgroup);
347	
348	        // Mask, and get row-wise max
349	        float cur_max = MAX_INIT_VAL;
350	        CUTLASS_PRAGMA_UNROLL
351	        for (int i = local_row_idx ? 2 : 0; i < size(rP0); i += 4) {
352	            if constexpr (DO_OOB_FILLING) {
353	                int token_idx = start_token_idx + (i/4)*8 + idx_in_warpgroup%4*2;
354	                rP0(i) = token_idx < rRightBorderForQSeq[local_row_idx] ? rP0(i) : MAX_INIT_VAL;
355	                rP0(i+1) = token_idx+1 < rRightBorderForQSeq[local_row_idx] ? rP0(i+1) : MAX_INIT_VAL;
356	            }
357	            cur_max = max(cur_max, max(rP0(i), rP0(i+1)));
358	        }
359	        cur_max = max(cur_max, __shfl_xor_sync(0xffffffff, cur_max, 1));
360	        cur_max = max(cur_max, __shfl_xor_sync(0xffffffff, cur_max, 2));
361	        
362	        // Update sM and sL
363	        cur_max *= scale_softmax_log2;
364	        float new_max = max(sM(row_idx), cur_max);
365	        float scale_for_old = exp2f(sM(row_idx) - new_max);
366	        __syncwarp();   // Make sure all reads have finished before updating sM
367	        if (idx_in_warpgroup%4 == 0) {
368	            sScale0(row_idx) = scale_for_old;
369	            sM(row_idx) = new_max;
370	        }
371	        
372	        // Scale-O
373	        CUTLASS_PRAGMA_UNROLL
374	        for (int i = local_row_idx ? 2 : 0; i < size(rO0); i += 4) {
375	            rO0(i) *= scale_for_old;
376	            rO0(i+1) *= scale_for_old;
377	        }
378	
379	        // Scale, exp, and get row-wise expsum
380	        float cur_sum = 0;
381	        CUTLASS_PRAGMA_UNROLL
382	        for (int i = local_row_idx ? 2 : 0; i < size(rP0); i += 4) {
383	            rP0(i) = exp2f(rP0(i)*scale_softmax_log2 - new_max);
384	            rP0(i+1) = exp2f(rP0(i+1)*scale_softmax_log2 - new_max);
385	            rPb(i) = (typename T::InputT)rP0(i);
386	            rPb(i+1) = (typename T::InputT)rP0(i+1);
387	            cur_sum += rP0(i) + rP0(i+1);
388	        }
389	        rL[local_row_idx] = rL[local_row_idx]*scale_for_old + cur_sum;
390	    }
391	}
