394	template<
395	    typename T,
396	    bool IS_BLK0_LAST,
397	    bool IS_BLK1_LAST,
398	    bool IS_BLK2_LAST,
399	    typename Engine0, typename Layout0,
400	    typename Engine1, typename Layout1,
401	    typename Engine2, typename Layout2,
402	    typename Engine3, typename Layout3,
403	    typename Engine4, typename Layout4,
404	    typename Engine5, typename Layout5
405	>
406	__forceinline__ __device__ void wg1_bunch_0(
407	    Tensor<Engine0, Layout0> &rP1b,	// ((2, 2, 8), 1, 1)
408	    Tensor<Engine1, Layout1> &sScale1,	// (BLOCK_SIZE_M)
409	    Tensor<Engine2, Layout2> &rO1,	// ((2, 2, 32), 1, 1)
410	    Tensor<Engine3, Layout3> &sM,	// (BLOCK_SIZE_M)
411	    float rL[2],
412	    int rRightBorderForQSeq[2],
413	    Tensor<Engine4, Layout4> const &sScale0,	// (BLOCK_SIZE_M)
414	    Tensor<Engine5, Layout5> &rP1,	// ((2, 2, 8), 1, 1)
415	    float scale_softmax_log2,
416	    int start_token_idx,
417	    int idx_in_warpgroup
418	) {
419	    CUTLASS_PRAGMA_UNROLL
420	    for (int local_row_idx = 0; local_row_idx < 2; ++local_row_idx) {
421	        int row_idx = get_AorC_row_idx(local_row_idx, idx_in_warpgroup);
422	
423	        // Mask, and get row-wise max
424	        float cur_max = MAX_INIT_VAL;
425	        CUTLASS_PRAGMA_UNROLL
426	        for (int i = local_row_idx ? 2 : 0; i < size(rP1); i += 4) {
427	            if constexpr (IS_BLK1_LAST || IS_BLK2_LAST) {
428	                // Need to apply the mask when either this block is the last one, or
429	                // the next block is the last one (because of the causal mask)
430	                int token_idx = start_token_idx + (i/4)*8 + idx_in_warpgroup%4*2;
431	                rP1(i) = token_idx < rRightBorderForQSeq[local_row_idx] ? rP1(i) : MAX_INIT_VAL;
432	                rP1(i+1) = token_idx+1 < rRightBorderForQSeq[local_row_idx] ? rP1(i+1) : MAX_INIT_VAL;
433	            } else if constexpr (IS_BLK0_LAST) {
434	                rP1(i) = rP1(i+1) = MAX_INIT_VAL;
435	            }
436	            cur_max = max(cur_max, max(rP1(i), rP1(i+1)));
437	        }
438	        cur_max = max(cur_max, __shfl_xor_sync(0xffffffff, cur_max, 1));
439	        cur_max = max(cur_max, __shfl_xor_sync(0xffffffff, cur_max, 2));
440	        cur_max *= scale_softmax_log2;
441	
442	        float old_max = sM(row_idx);
443	        float new_max = max(old_max, cur_max);
444	        float scale_for_old = exp2f(old_max - new_max);
445	        __syncwarp();
446	        if (idx_in_warpgroup%4 == 0) {
447	            sM(row_idx) = new_max;
448	            sScale1(row_idx) = scale_for_old;
449	        }
450	
451	        // Scale, exp, and get row-wise expsum
452	        float cur_sum = 0;
453	        if constexpr (!IS_BLK0_LAST) {
454	            CUTLASS_PRAGMA_UNROLL
455	            for (int i = local_row_idx ? 2 : 0; i < size(rP1); i += 4) {
456	                rP1(i) = exp2f(rP1(i)*scale_softmax_log2 - new_max);
457	                rP1(i+1) = exp2f(rP1(i+1)*scale_softmax_log2 - new_max);
458	                rP1b(i) = (typename T::InputT)rP1(i);
459	                rP1b(i+1) = (typename T::InputT)rP1(i+1);
460	                cur_sum += rP1(i) + rP1(i+1);
461	            }
462	        }
463	
464	        // Scale O
465	        float cur_scale_for_o1 = scale_for_old * sScale0(row_idx);
466	        CUTLASS_PRAGMA_UNROLL
467	        for (int i = local_row_idx ? 2 : 0; i < size(rO1); i += 4) {
468	            rO1(i) *= cur_scale_for_o1;
469	            rO1(i+1) *= cur_scale_for_o1;
470	        }
471	
472	        // Update rL
473	        rL[local_row_idx] = rL[local_row_idx]*cur_scale_for_o1 + cur_sum;
474	    }
475	}
