524	    typename T,
525	    typename Engine0, typename Layout0,
526	    typename Engine1, typename Layout1,
527	    typename Engine2, typename Layout2
528	>
529	__forceinline__ __device__ void wg0_scale_rP0(
530	    Tensor<Engine0, Layout0> const &sScale1,	// (BLOCK_M)
