587	            GMMA::Layout_MN_SW128_Atom<cute::int64_t>{},
588	            Shape<Int<256/(64/16)>, Int<T::PAGE_BLOCK_SIZE>>{},
589	            LayoutRight{}
590	        )
591	    );
592	    valid_window_size = max(valid_window_size, 0);
593	    int head_dim_size = size<0>(sV_int64);	// 128%head_dim_size == 0 should holds
594	    for (int token_idx = valid_window_size + (idx_in_warpgroup/head_dim_size); token_idx < size<1>(sV); token_idx += (128/head_dim_size)) {
595	        sV_int64(idx_in_warpgroup%head_dim_size, token_idx) = 0;
