600	// Store O / OAccum
601	template<
602	    typename T,
603	    bool IS_NO_SPLIT,
604	    typename TMAParams,
605	    typename Engine0, typename Layout0,
606	    typename Engine1, typename Layout1
607	>
608	__forceinline__ __device__ void store_o(
609	    Tensor<Engine0, Layout0> &rO,	// ((2, 2, 32), 1, 1)
610	    Tensor<Engine1, Layout1> &gOorAccum,	// (BLOCK_SIZE_M, HEAD_DIM_V)
611	    float rL[2],
612	    char* sO_addr,
613	    TMAParams &tma_params,
614	    int batch_idx,
615	    int k_head_idx,
616	    int m_block_idx,
617	    int num_valid_seq_q,
618	    int warpgroup_idx,
619	    int idx_in_warpgroup
620	) {
621	    using InputT = typename T::InputT;
622	    if constexpr (IS_NO_SPLIT) {
623	        // Should convert the output to bfloat16 / float16, and save it to O
624	        Tensor sOutputBuf = make_tensor(make_smem_ptr((InputT*)sO_addr), tile_to_shape(
625	            GMMA::Layout_K_SW128_Atom<InputT>{},
626	            Shape<Int<T::BLOCK_SIZE_M>, Int<T::HEAD_DIM_V>>{}
627	        ));
628	
629	        Tensor rOb = make_tensor_like<InputT>(rO);
630	        CUTLASS_PRAGMA_UNROLL
631	        for (int idx = 0; idx < size(rO); ++idx) {
632	            rOb(idx) = (InputT)(rO(idx) / rL[idx%4 >= 2]);
633	        }
634	
635	        Tensor sMyOutputBuf = local_tile(sOutputBuf, Shape<_64, _256>{}, make_coord(_0{}, warpgroup_idx));
636	        TiledCopy r2s_tiled_copy = make_tiled_copy_C(
637	            Copy_Atom<SM90_U32x4_STSM_N, InputT>{},
638	            (typename T::TiledMMA_PV_LocalP){}
639	        );
640	        ThrCopy r2s_thr_copy = r2s_tiled_copy.get_slice(idx_in_warpgroup);
641	        Tensor r2s_thr_copy_rOb = r2s_thr_copy.retile_S(rOb);
642	        Tensor r2s_thr_copy_sMyOutputBuf = r2s_thr_copy.partition_D(sMyOutputBuf);
643	        cute::copy(r2s_tiled_copy, r2s_thr_copy_rOb, r2s_thr_copy_sMyOutputBuf);
644	        cutlass::arch::fence_view_async_shared();
645	        
646	        __syncthreads();
647	
648	        if (threadIdx.x == 0) {
649	            Tensor tma_gO = tma_params.tma_O.get_tma_tensor(tma_params.shape_O)(_, _, k_head_idx, batch_idx);	// (seqlen_q, HEAD_DIM)
650	            auto thr_tma = tma_params.tma_O.get_slice(_0{});
651	            Tensor my_tma_gO = flat_divide(tma_gO, Shape<Int<T::BLOCK_SIZE_M>, Int<T::HEAD_DIM_V>>{})(_, _, m_block_idx, _0{});
652	            cute::copy(
653	                tma_params.tma_O,
654	                thr_tma.partition_S(sOutputBuf),
655	                thr_tma.partition_D(my_tma_gO)
656	            );
657	            cute::tma_store_arrive();
658	        }
659	    } else {
660	        // Should save the result to OAccum
661	        Tensor sOutputBuf = make_tensor(make_smem_ptr((float*)sO_addr), Layout<
662	            Shape<_64, _512>,
663	            Stride<Int<520>, _1>	// We use stride = 520 here to avoid bank conflict
664	        >{});
665	    
666	        CUTLASS_PRAGMA_UNROLL
667	        for (int idx = 0; idx < size(rO); idx += 2) {
668	            int row = (idx_in_warpgroup/32)*16 + (idx_in_warpgroup%32/4) + (idx%4 >= 2 ? 8 : 0);
669	            int col = warpgroup_idx*256 + (idx_in_warpgroup%4)*2 + idx/4*8;
670	            *(float2*)((float*)sO_addr + sOutputBuf.layout()(row, col)) = float2 {
671	                rO(idx) / rL[idx%4 >= 2],
672	                rO(idx+1) / rL[idx%4 >= 2],
673	            };
674	        }
675	        cutlass::arch::fence_view_async_shared();
676	        
677	        __syncthreads();
678	        
679	        int row = threadIdx.x;
680	        if (row < num_valid_seq_q) {
681	            SM90_BULK_COPY_S2G::copy(&sOutputBuf(row, _0{}), &gOorAccum(row, _0{}), T::HEAD_DIM_V*sizeof(float));
682	            cute::tma_store_arrive();
683	        }
684	    }
685	}
