724	template<
725	    typename T,
726	    bool IS_BLK0_LAST,	// "BLK0" means block_idx+0, "BLK1" means block_idx+1, ...
727	    bool IS_BLK1_LAST,
728	    typename TMAParams,
729	    typename Engine0, typename Layout0,
730	    typename Engine1, typename Layout1,
731	    typename Engine2, typename Layout2,
732	    typename Engine3, typename Layout3,
733	    typename Engine4, typename Layout4,
734	    typename Engine5, typename Layout5,
735	    typename Engine6, typename Layout6,
736	    typename Engine7, typename Layout7,
737	    typename Engine8, typename Layout8,
738	    typename Engine9, typename Layout9,
739	    typename Engine10, typename Layout10,
740	    typename Engine11, typename Layout11
741	>
742	__forceinline__ __device__ void wg0_subroutine(
743	    Tensor<Engine0, Layout0> &tma_gK,
744	    Tensor<Engine1, Layout1> &sQ,
745	    Tensor<Engine2, Layout2> &sK0,
746	    Tensor<Engine3, Layout3> &sK1,
747	    Tensor<Engine4, Layout4> &sP0,
748	    Tensor<Engine5, Layout5> &sP1,
749	    Tensor<Engine6, Layout6> &sM,
750	    Tensor<Engine7, Layout7> &sScale0,
751	    Tensor<Engine8, Layout8> &sScale1,
752	    Tensor<Engine9, Layout9> &rQ8,
753	    Tensor<Engine10, Layout10> &rP0,
754	    Tensor<Engine11, Layout11> &rO0,
755	    float rL[2],
756	    int rRightBorderForQSeq[2],
757	    TMABarrier barriers_K0[9],
758	    TMABarrier barriers_K1[9],
759	    bool &cur_phase_K0,
760	    const TMAParams &tma_params,
761	    const DenseAttnDecodeParams &params,
762	    int* block_table_ptr,
763	    int seqlen_k,
764	    int block_idx,
765	    int end_block_idx,
766	    int idx_in_warpgroup
767	) {
768	    int start_token_idx = block_idx * T::PAGE_BLOCK_SIZE;
769	    #define GET_BLOCK_INDEX(block_idx) ((block_idx) >= end_block_idx ? 0 : __ldg(block_table_ptr + (block_idx)))
770	    int nxt_block0_index = GET_BLOCK_INDEX(block_idx+2);
771	    int nxt_block1_index = GET_BLOCK_INDEX(block_idx+3);
772	
773	    Tensor sV0L = get_half_V<T, 0>(sK0);
774	    Tensor sV1L = get_half_V<T, 0>(sK1);
775	
776	    Tensor rPb = make_tensor<T::InputT>(Shape<Shape<_2, _2, _2>, _1, _4>{});
777	    // Calc P0 = softmax(P0)
778	    wg0_bunch_0<T, IS_BLK0_LAST||IS_BLK1_LAST>(rPb, rP0, rO0, sScale0, sM, rL, rRightBorderForQSeq, params.scale_softmax_log2, start_token_idx, idx_in_warpgroup);
779	    NamedBarrier::arrive(T::NUM_THREADS, NamedBarriers::sScale0Ready);
780	
781	    // Issue rO0 += rPb @ sV0L
782	    if constexpr (IS_BLK0_LAST) {
783	        fill_oob_V<T>(sV0L, seqlen_k-start_token_idx, idx_in_warpgroup);
784	        cutlass::arch::fence_view_async_shared();
785	    }
786	    warpgroup_cooperative_pv_gemm_localP<T>(rPb, sV0L, rO0, idx_in_warpgroup);
787	
788	    // Wait for rO0, launch TMA for the next V0L
789	    cute::warpgroup_wait<0>();
790	    
791	    // Wait for warpgroup 1, rescale P0, notify warpgroup 1
792	    NamedBarrier::arrive_and_wait(T::NUM_THREADS, NamedBarriers::sScale1Ready);
793	    if constexpr (!IS_BLK0_LAST && !IS_BLK1_LAST) {
794	        // Put it here seems to be faster, don't know why
795	        launch_kv_tiles_copy_tma<0, 4>(tma_gK(_, _, nxt_block0_index), sK0, tma_params.tma_K, barriers_K0, idx_in_warpgroup);
796	    }
797	    wg0_scale_rP0<T>(sScale1, rP0, rPb, idx_in_warpgroup);
798	    save_rPb_to_sP<T>(rPb, sP0, idx_in_warpgroup);
799	    cutlass::arch::fence_view_async_shared();
800	    NamedBarrier::arrive(T::NUM_THREADS, NamedBarriers::sP0Ready);
801	    
802	    // Wait for warpgroup 1, rescale O0, issue rO0 += rPb @ sV1L
803	    if constexpr (!IS_BLK0_LAST) {
804	        if constexpr (IS_BLK1_LAST) {
805	            fill_oob_V<T>(sV1L, seqlen_k-start_token_idx-T::PAGE_BLOCK_SIZE, idx_in_warpgroup);
806	            cutlass::arch::fence_view_async_shared();
807	        }
808	        NamedBarrier::arrive_and_wait(T::NUM_THREADS, NamedBarriers::rO1sP0sV0RIssued);
809	        wg0_rescale_rO0(rO0, sScale1, rL, idx_in_warpgroup);
810	        warpgroup_cooperative_pv_gemm_remoteP<T>(sP1, sV1L, rO0, idx_in_warpgroup);
811	    }
812	    
813	    // Issue P0 = Q @ K0^T
814	    // Since TMAs for these 4 tiles are launched right after rO0 += rPb @ sV0L finishes, they should have already finished. Therefore, we issue the first 4 tiles to fill the pipeline.
815	    if constexpr (!IS_BLK0_LAST && !IS_BLK1_LAST) {
816	        warpgroup_cooperative_qkt_gemm<T, 0>(sQ, sK0, rP0, rQ8, barriers_K0, cur_phase_K0, idx_in_warpgroup);
817	    }
818	
819	    // Wait for rO0 += rPb @ sV1L, launch TMA
820	    if (!IS_BLK0_LAST && !IS_BLK1_LAST && __builtin_expect(block_idx+3 < end_block_idx, true)) {
821	        cute::warpgroup_wait<4>();
822	        launch_kv_tiles_copy_tma<0, 4>(tma_gK(_, _, nxt_block1_index), sK1, tma_params.tma_K, barriers_K1, idx_in_warpgroup);
823	    }
824	    
825	    // Issue P0 = Q @ K0^T
826	    if constexpr (!IS_BLK0_LAST && !IS_BLK1_LAST) {
827	        warpgroup_cooperative_qkt_gemm<T, 2>(sQ, sK0, rP0, rQ8, barriers_K0, cur_phase_K0, idx_in_warpgroup);
828	    }
829	    
830	    // Wait for P0 = Q @ K0^T
831	    cute::warpgroup_wait<0>();
832	}
