835	template<
836	    typename T,
837	    bool IS_BLK0_LAST,
838	    bool IS_BLK1_LAST,
839	    bool IS_BLK2_LAST,
840	    typename TMAParams,
841	    typename Engine0, typename Layout0,
842	    typename Engine1, typename Layout1,
843	    typename Engine2, typename Layout2,
844	    typename Engine3, typename Layout3,
845	    typename Engine4, typename Layout4,
846	    typename Engine5, typename Layout5,
847	    typename Engine6, typename Layout6,
848	    typename Engine7, typename Layout7,
849	    typename Engine8, typename Layout8,
850	    typename Engine9, typename Layout9,
851	    typename Engine10, typename Layout10,
852	    typename Engine11, typename Layout11
853	>
854	__forceinline__ __device__ void wg1_subroutine(
855	    Tensor<Engine0, Layout0> &tma_gK,
856	    Tensor<Engine1, Layout1> &sQ,
857	    Tensor<Engine2, Layout2> &sK0,
858	    Tensor<Engine3, Layout3> &sK1,
859	    Tensor<Engine4, Layout4> &sP0,
860	    Tensor<Engine5, Layout5> &sP1,
861	    Tensor<Engine6, Layout6> &sM,
862	    Tensor<Engine7, Layout7> &sScale0,
863	    Tensor<Engine8, Layout8> &sScale1,
864	    Tensor<Engine9, Layout9> &rQ8,
865	    Tensor<Engine10, Layout10> &rP1,
866	    Tensor<Engine11, Layout11> &rO1,
867	    float rL[2],
868	    int rRightBorderForQSeq[2],
869	    TMABarrier barriers_K0[9],
870	    TMABarrier barriers_K1[9],
871	    bool &cur_phase_K1,
872	    const TMAParams &tma_params,
873	    const DenseAttnDecodeParams &params,
874	    int* block_table_ptr,
875	    int seqlen_k,
876	    int block_idx,
877	    int end_block_idx,
878	    int idx_in_warpgroup
879	) {
880	    int start_token_idx = block_idx * T::PAGE_BLOCK_SIZE;
881	    int nxt_block0_index = GET_BLOCK_INDEX(block_idx+2);
882	    int nxt_block1_index = GET_BLOCK_INDEX(block_idx+3);
883	
884	    Tensor rP1b = make_tensor<T::InputT>(Shape<Shape<_2, _2, _2>, _1, _4>{});
885	    
886	    Tensor sV0R = get_half_V<T, 1>(sK0);
887	    Tensor sV1R = get_half_V<T, 1>(sK1);
888	
889	    // Wait for rP1 and warpgroup 0, run bunch 1, notify warpgroup 0
890	    NamedBarrier::arrive_and_wait(T::NUM_THREADS, NamedBarriers::sScale0Ready);
891	    wg1_bunch_0<T, IS_BLK0_LAST, IS_BLK1_LAST, IS_BLK2_LAST>(rP1b, sScale1, rO1, sM, rL, rRightBorderForQSeq, sScale0, rP1, params.scale_softmax_log2, start_token_idx+T::PAGE_BLOCK_SIZE, idx_in_warpgroup);
892	    NamedBarrier::arrive(T::NUM_THREADS, NamedBarriers::sScale1Ready);
893	
894	    // Save rPb to sP, and issue rO1 += rP1b @ sV1R
895	    // We do this after notifying warpgroup 1, since both "saving rPb to sP" and "issuing" WGMMA are high-latency operations
896	    if constexpr (!IS_BLK0_LAST) {
897	        save_rPb_to_sP<T>(rP1b, sP1, idx_in_warpgroup);
898	    }
899	    if constexpr (!IS_BLK0_LAST) {
900	        if constexpr (IS_BLK1_LAST) {
901	            fill_oob_V<T>(sV1R, seqlen_k-start_token_idx-T::PAGE_BLOCK_SIZE, idx_in_warpgroup);
902	            cutlass::arch::fence_view_async_shared();
903	        }
904	        warpgroup_cooperative_pv_gemm_localP<T>(rP1b, sV1R, rO1, idx_in_warpgroup);
905	        if constexpr (!IS_BLK1_LAST) {
906	            // We use this proxy for making sP1 visible to the async proxy
907	            // We skip it if IS_BLK1_LAST, since in that case we have already put a fence
908	            cutlass::arch::fence_view_async_shared();
909	        }
910	    }
911	    
912	    // Wait for sP0, issue rO1 += sP0 @ sV0R, notify warpgroup 0
913	    NamedBarrier::arrive_and_wait(T::NUM_THREADS, NamedBarriers::sP0Ready);
914	    if constexpr (IS_BLK0_LAST) {
915	        fill_oob_V<T>(sV0R, seqlen_k-start_token_idx, idx_in_warpgroup);
916	        cutlass::arch::fence_view_async_shared();
917	    }
918	    warpgroup_cooperative_pv_gemm_remoteP<T>(sP0, sV0R, rO1, idx_in_warpgroup);
919	    if constexpr (!IS_BLK0_LAST) {
920	        NamedBarrier::arrive(T::NUM_THREADS, NamedBarriers::rO1sP0sV0RIssued);
921	    }
922	    
923	    // Wait for rO1 += rP1b @ sV1R, launch TMA for the next V1R
924	    if constexpr (!IS_BLK0_LAST && !IS_BLK1_LAST && !IS_BLK2_LAST) {
925	        cute::warpgroup_wait<1>();
926	        launch_kv_tiles_copy_tma<4, 9>(tma_gK(_, _, nxt_block1_index), sK1, tma_params.tma_K, barriers_K1, idx_in_warpgroup);
927	    }
928	    
929	    // Wait for rO1 += sP0 @ sV0R, launch TMA for the next V0R
930	    if constexpr (!IS_BLK0_LAST && !IS_BLK1_LAST) {
931	        cute::warpgroup_wait<0>();
932	        launch_kv_tiles_copy_tma<4, 9>(tma_gK(_, _, nxt_block0_index), sK0, tma_params.tma_K, barriers_K0, idx_in_warpgroup);
933	    }
934	
935	    if constexpr (!IS_BLK0_LAST && !IS_BLK1_LAST && !IS_BLK2_LAST) {
936	        // Issue rP1 = sQ @ sK1, wait
937	        warpgroup_cooperative_qkt_gemm<T, 1>(sQ, sK1, rP1, rQ8, barriers_K1, cur_phase_K1, idx_in_warpgroup);
938	    }
939	    
940	    // We put the `cute::warpgroup_wait<0>()` out of the `if` statement above, otherwise
941	    // nvcc cannot correctly analyse the loop, and will think that we are using accumulator
942	    // registers during the WGMMA pipeline, which results in `WARPGROUP.ARRIVE` and `WARPGROUP.DEPBAR.LE` being inserted in SASS and WGMMA instructions being serialized.
943	    // This is also the reason why we put QK^T here, instead of the first operation in the loop
944	    cute::warpgroup_wait<0>();
945	}
