947	// A helper function for determining the length of the causal mask for one q token
948	__forceinline__ __device__ int get_mask_len(const DenseAttnDecodeParams &params, int m_block_idx, int local_seq_q_idx) {
949	    int global_seq_q_idx = m_block_idx*Config::BLOCK_SIZE_M + local_seq_q_idx;
950	    if (global_seq_q_idx < params.q_seq_per_hk) {
951	        int s_q_idx = global_seq_q_idx / params.q_head_per_hk;
952	        return params.s_q - s_q_idx - 1;
953	    } else {
954	        // Out-of-bound request, regard as no masks
955	        return 0;
956	    }
957	}
