959	template<typename T, typename TmaParams>
960	__global__ void __launch_bounds__(T::NUM_THREADS, 1, 1)
961	flash_fwd_splitkv_mla_kernel(__grid_constant__ const DenseAttnDecodeParams params, __grid_constant__ const TmaParams tma_params) {
962	    // grid shape: [
963	    // 	num_m_blocks (=ceil_div(seqlen_q_ori*(num_q_heads//num_kv_heads))),
964	    // 	num_kv_heads,
965	    // 	num_sm_parts
966	    // ]
967	    // An "sm part" is responsible for all the BLOCK_SIZE_M q_heads in the m_block (as specified by m_block_idx), under one kv head (as specified by k_head_idx), of a segment (as specified by [start_block_idx, end_block_idx]) of one request (as specified by batch_idx).
968	    // If is_no_split is True, then this request is exclusively assigned to this sm_part, so we shall write the result directly into params.o_ptr and params.softmax_lse_ptr. Otherwise, write to oaccum_ptr and softmax_lseaccum_ptr, with the corresponding split idx being (n_split_idx + num_splits_ptr[batch_idx])
969	    // For the complete schedule of the kernel, please read our deep-dive write-up (link can be found in the README.md file).
970	
971	#if (defined(__CUDA_ARCH__) && (__CUDA_ARCH__ == 900)) || (defined(__CLION_IDE__) || defined(__VSCODE_IDE__))
972	    const int m_block_idx = blockIdx.x;
973	    const int k_head_idx = blockIdx.y;
974	    const int partition_idx = blockIdx.z;
975	    const int warpgroup_idx = threadIdx.x / 128;
976	    const int idx_in_warpgroup = threadIdx.x % 128;
977	
978	    // Define shared tensors
979	    extern __shared__ char wksp_buf[];
980	    using SharedMemoryPlan = typename T::SharedMemoryPlan;
981	    SharedMemoryPlan &plan = *reinterpret_cast<SharedMemoryPlan*>(wksp_buf);
982	    Tensor sQ = make_tensor(make_smem_ptr(plan.smem_sQ.data()), (typename T::SmemLayoutQ){});
983	    Tensor sK0 = make_tensor(make_smem_ptr(plan.smem_sK0.data()), (typename T::SmemLayoutK){});
984	    Tensor sK1 = make_tensor(make_smem_ptr(plan.smem_sK1.data()), (typename T::SmemLayoutK){});
985	    Tensor sP0 = make_tensor(make_smem_ptr(plan.smem_sP0.data()), (typename T::SmemLayoutP0){});
986	    Tensor sP1 = flat_divide(sQ, Shape<Int<T::BLOCK_SIZE_M>, Int<T::PAGE_BLOCK_SIZE>>{})(_, _, _0{}, _8{}); // Overlap with sQ's 8-th tile
987	    Tensor sM = make_tensor(make_smem_ptr(plan.smem_sM.data()), make_shape(Int<T::BLOCK_SIZE_M>{}));
988	    Tensor sL_reduction_wksp = make_tensor(make_smem_ptr(plan.sL_reduction_wksp.data()), make_shape(Int<2*T::BLOCK_SIZE_M>{}));
989	    Tensor sScale0 = make_tensor(make_smem_ptr(plan.smem_sScale0.data()), make_shape(Int<T::BLOCK_SIZE_M>{}));
990	    Tensor sScale1 = make_tensor(make_smem_ptr(plan.smem_sScale1.data()), make_shape(Int<T::BLOCK_SIZE_M>{}));
991	    char* sO_addr = (char*)plan.smem_sK0.data();	// Overlap with sK0 and sK1
992	    
993	    // Prefetch TMA descriptors
994	    if (threadIdx.x == 0) {
995	        cute::prefetch_tma_descriptor(tma_params.tma_Q.get_tma_descriptor());
996	        cute::prefetch_tma_descriptor(tma_params.tma_K.get_tma_descriptor());
997	        cute::prefetch_tma_descriptor(tma_params.tma_O.get_tma_descriptor());
998	    }
999	
1000	    // Define TMA stuffs
1001	    Tensor tma_gK = tma_params.tma_K.get_tma_tensor(tma_params.shape_K)(_, _, k_head_idx, _);
1002	    TMABarrier* barriers_K0 = plan.barriers_K0;
1003	    TMABarrier* barriers_K1 = plan.barriers_K1;
1004	    TMABarrier* barrier_Q = &(plan.barrier_Q);
1005	
1006	    // Initialize TMA barriers
1007	    if (threadIdx.x == 0) {
1008	        barrier_Q->init(1);
1009	        CUTLASS_PRAGMA_UNROLL
1010	        for (int i = 0; i < 9; ++i) {
1011	            barriers_K0[i].init(1);
1012	            barriers_K1[i].init(1);
1013	        }
1014	        cutlass::arch::fence_view_async_shared();
1015	    }
1016	    __syncthreads();
1017	    bool cur_phase_Q = 0, cur_phase_K0 = 0, cur_phase_K1 = 0;
1018	
1019	    
1020	    DecodingSchedMeta sched_meta = params.tile_scheduler_metadata_ptr[partition_idx];
1021	    if (sched_meta.begin_req_idx >= params.b) return;
1022	
1023	    // Copy the first Q
1024	    launch_q_copy<T>(tma_params, sched_meta.begin_req_idx, m_block_idx, k_head_idx, sQ, barrier_Q);
1025	
1026	    #pragma unroll 1
1027	    for (int batch_idx = sched_meta.begin_req_idx; batch_idx <= sched_meta.end_req_idx; ++batch_idx) {
1028	        constexpr int kBlockN = T::PAGE_BLOCK_SIZE;
1029	        const int n_split_idx = batch_idx == sched_meta.begin_req_idx ? sched_meta.begin_split_idx : 0;
1030	        int seqlen_k = __ldg(params.seqlens_k_ptr + batch_idx);
1031	        const int start_block_idx = batch_idx == sched_meta.begin_req_idx ? sched_meta.begin_block_idx : 0;
1032	        int end_block_idx = batch_idx == sched_meta.end_req_idx ? sched_meta.end_block_idx : cute::ceil_div(seqlen_k, kBlockN);
1033	        const bool is_no_split = batch_idx == sched_meta.begin_req_idx ? !sched_meta.is_first_req_splitted : (batch_idx == sched_meta.end_req_idx ? !sched_meta.is_last_req_splitted : true);
1034	        
1035	        int rRightBorderForQSeq[2];
1036	        if (params.is_causal) {
1037	            // The causal mask looks like:
1038	            // XXXX
1039	            // XXXX
1040	            // ...
1041	            // XXXX
1042	            //  XXX
1043	            //  XXX
1044	            //  ...
1045	            //  XXX
1046	            //   XX
1047	            //   XX
1048	            //  ...
1049	            //   XX
1050	            // Firstly, there is a common_mask_len, which is the minimum length of causal masks among all tokens. Since the length of the causal mask decreases monotonically, the common_mask_len is the length of the causal mask for the last token. We consider the common_mask_len as a "reduction in the length of the k-sequence.", and adjust end_block_idx based on it, to save some calculation.
1051	            // Besides, a token may have some extra masks other than the common mask. We use rRightBorderForQSeq to denote it, which means the right border of the k-sequence for the particular q token. In this way, (seqlen_k-common_mask_len) - rRightBorderForQSeq < 64 holds, which means that we only need to apply the causal mask to the last two KV blocks
1052	            // NOTE This may lead to start_block_idx >= end_block_idx which needs some special handling
1053	            int common_mask_len = get_mask_len(params, m_block_idx, T::BLOCK_SIZE_M-1);
1054	            int last_block_in_seq = cute::ceil_div(seqlen_k-common_mask_len, kBlockN);
1055	            end_block_idx = batch_idx == sched_meta.end_req_idx ? min(sched_meta.end_block_idx, last_block_in_seq) : last_block_in_seq;
1056	
1057	            CUTLASS_PRAGMA_UNROLL
1058	            for (int local_row_idx = 0; local_row_idx < 2; ++local_row_idx) {
